// 把最後心跳時刻存進 workflow static data（production 執行才會持久化）
const sd = $getWorkflowStaticData('global');
sd.lastHeartbeat = Date.now();
const body = $input.first().json.body || $input.first().json || {};
sd.lastHeartbeatText = body.ts || new Date().toISOString();
return [{ json: { ok: true, saved: sd.lastHeartbeatText } }];

// 檢查心跳新鮮度：超過2小時沒更新 = 系統可能掛了（門市電腦被關/程序消失/整天斷網）
// 檢查排程只落在 10:00~22:00——每晚 00:00~約07:22 門市固定斷網，心跳暫停屬正常，
// 不能在那段時間判死刑；10:00 檢查時若系統正常，心跳早已恢復（07:2x 起每10分鐘一跳）。
const sd = $getWorkflowStaticData('global');
const last = sd.lastHeartbeat || 0;
const ageMin = last ? Math.round((Date.now() - last) / 60000) : null;
const THRESHOLD_MIN = 120;

if (last && ageMin < THRESHOLD_MIN) {
  return [];  // 心跳新鮮 → 不吵你
}

const lastText = sd.lastHeartbeatText || '（從未收到——可能剛匯入還沒收過心跳，或 grab.py 沒在跑）';
const text = `⚠ KEIS 搶單系統沒心跳\n最後心跳：${lastText}` +
  (ageMin != null ? `（${Math.floor(ageMin / 60)} 小時 ${ageMin % 60} 分前）` : '') +
  `\n\n可能原因：門市電腦被關機／grab.py 程序消失／網路整天斷線\n請回店裡看一下黑視窗還在不在，或重跑 run.bat`;
return [{ json: { text } }];
